import{_ as p,r as o,o as c,c as l,a as n,d as a,b as t,e}from"./app-641f5373.js";const i={},u=e(`<h2 id="基本引用类型" tabindex="-1"><a class="header-anchor" href="#基本引用类型" aria-hidden="true">#</a> 基本引用类型</h2><p>引用值（或者对象）是某个特定<strong>引用类型</strong>的实例</p><h3 id="date" tabindex="-1"><a class="header-anchor" href="#date" aria-hidden="true">#</a> Date</h3><p>Date 对象基于 Unix Time Stamp，即自 1970 年 1 月 1 日（UTC）起经过的毫秒数</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 实例化时刻的日期和时间</span>
<span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// value 表示 1970 年 1 月 1 日（UTC）起经过的毫秒数</span>
<span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span>dateString<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// dateString 表示日期字符串，该字符串应该能被 Date.parse() 正确方法识别</span>
<span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span>year<span class="token punctuation">,</span> monthIndex <span class="token punctuation">[</span><span class="token punctuation">,</span> day <span class="token punctuation">[</span><span class="token punctuation">,</span> hours <span class="token punctuation">[</span><span class="token punctuation">,</span> minutes <span class="token punctuation">[</span><span class="token punctuation">,</span> seconds <span class="token punctuation">[</span><span class="token punctuation">,</span> milliseconds<span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Date.now()，返回自 1970-1-1 00:00:00 UTC（世界标准时间）至今所经过的毫秒数</li><li>Date.parse()，接收一个表示日期的字符串参数，然后尝试根据这个字符串返回相应日期的毫秒数</li><li>Date.UTC()，接收年份、基于 0 的月份（一月是 0，二月是 1，以此类推）、月中的哪一天（1 到 31）、小时数（0 到 23）、分钟、秒以及毫秒数，返回表示这个日期的毫秒数</li></ul><h4 id="继承的方法" tabindex="-1"><a class="header-anchor" href="#继承的方法" aria-hidden="true">#</a> 继承的方法</h4><ul><li>toLocaleString()，返回与浏览器运行的本地环境相适应的日期和时间</li><li>toString()，返回带有时区信息的日期和时间</li><li>valueOf()，返回日期的毫秒表示，故操作符（如 &lt;）可以直接使用它返回的值</li></ul><h4 id="日期格式化方法" tabindex="-1"><a class="header-anchor" href="#日期格式化方法" aria-hidden="true">#</a> 日期格式化方法</h4><p>Date 类型有几个专门用于格式化日期的方法，它们都会返回字符串</p><ul><li>toDateString()，以特定于实现的格式显示星期几、月、日和年</li><li>toTimeString()，以特定于实现的格式显示时、分、秒和时区</li><li>toLocaleDateString()，以特定于实现和地区的格式显示星期几、月、日和年</li><li>toLocaleTimeString()，以特定于实现和地区的格式显示时、分、秒</li><li>toUTCString()，以特定于实现的格式完整的 UTC 日期</li></ul><blockquote><p>这些方法的输出与 toLocaleString() 和 toString() 一样，会因浏览器而异，因此不能用于在用户界面上一致的显示日期</p></blockquote>`,12),r={href:"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Date#%E5%AE%9E%E4%BE%8B%E6%96%B9%E6%B3%95",target:"_blank",rel:"noopener noreferrer"},k=e(`<h3 id="regexp" tabindex="-1"><a class="header-anchor" href="#regexp" aria-hidden="true">#</a> RegExp</h3><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> expression <span class="token operator">=</span> <span class="token operator">/</span>pattern<span class="token operator">/</span>flags<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,2),d={href:"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/RegExp#%E5%AE%9E%E4%BE%8B%E5%B1%9E%E6%80%A7",target:"_blank",rel:"noopener noreferrer"},m={href:"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/RegExp#%E5%AE%9E%E4%BE%8B%E6%96%B9%E6%B3%95",target:"_blank",rel:"noopener noreferrer"},v={href:"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/RegExp#%E9%9D%99%E6%80%81%E5%B1%9E%E6%80%A7",target:"_blank",rel:"noopener noreferrer"},g=e(`<h3 id="原始值包装类型" tabindex="-1"><a class="header-anchor" href="#原始值包装类型" aria-hidden="true">#</a> 原始值包装类型</h3><p>每当用到某个原始值的方法或属性时，后台都会创建一个相应原始包装类型的对象，从而暴露出操作原始值的各种方法</p><p>引用类型与原始包装类型的主要区别在于对象的生命周期。在通过 new 实例化引用类型后，得到的实例会在离开作用域时被销毁，而自动创建的原始值包装对象则只存在于访问它的那行代码执行期间。这意味着不能在运行时给原始值添加属性和方法，比如：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> name <span class="token operator">=</span> <span class="token string">&#39;Nicholas&#39;</span>
name<span class="token punctuation">.</span>age <span class="token operator">=</span> <span class="token number">27</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>name<span class="token punctuation">.</span>age<span class="token punctuation">)</span> <span class="token comment">// undefined</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以显示地使用 Boolean、Number 和 String 创建原始值包装对象，实例上调用 typeof 会返回 object</p><p>原始值和包装对象之间的区别：</p><ul><li>typeof 操作符对包装对象返回 &#39;object&#39;</li><li>包装对象在使用 instanceof 操作符时返回 true，而原始值则不是</li></ul><h4 id="boolean" tabindex="-1"><a class="header-anchor" href="#boolean" aria-hidden="true">#</a> Boolean</h4><p>要创建一个 Boolean 对象，就使用 Boolean 构造函数并传入 true 或 false</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> booleanObject <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Boolean</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>valueOf()，返回原始值 true 或 false</li><li>toString()，返回字符串 &#39;true&#39; 或 &#39;false&#39;</li></ul><h4 id="number" tabindex="-1"><a class="header-anchor" href="#number" aria-hidden="true">#</a> Number</h4><p>要创建一个 Number 对象，就使用 Number 构造函数并传入数值</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> numberObject <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Number</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>继承的方法：</p><ul><li>valueOf()，返回原始值</li><li>toString() / toLocaleString()，返回字符串形式的数值</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> num <span class="token operator">=</span> <span class="token number">10</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>num<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;10&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>num<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;1010&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>num<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token number">8</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;12&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>num<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;10&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>num<span class="token punctuation">.</span><span class="token function">toString</span><span class="token punctuation">(</span><span class="token number">16</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;a&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>格式化数值：</p><ul><li>toFixed()，按指定的小数位返回数值的字符串表示</li><li>toExponential()，按指定的小数位返回数值的字符串表示，以科学计数法表示</li><li>toPrecision()，按指定的有效数位返回数值的字符串表示</li></ul><p>isInteger() 方法与安全整数：</p><ul><li>Number.isInteger()，判断数值是否为整数<div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token function">isInteger</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token function">isInteger</span><span class="token punctuation">(</span><span class="token number">1.0</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token function">isInteger</span><span class="token punctuation">(</span><span class="token number">1.1</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li>Number.isSafeInteger()，判断数值是否为安全整数<div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token function">isSafeInteger</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token constant">MAX_SAFE_INTEGER</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// true</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token function">isSafeInteger</span><span class="token punctuation">(</span>Number<span class="token punctuation">.</span><span class="token constant">MAX_SAFE_INTEGER</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// false</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h4 id="string" tabindex="-1"><a class="header-anchor" href="#string" aria-hidden="true">#</a> String</h4><p>要创建一个 String 对象，就使用 String 构造函数并传入字符串</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> stringObject <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">String</span><span class="token punctuation">(</span><span class="token string">&#39;hello world&#39;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>继承的方法：</p><ul><li>valueOf() / toLocaleString() / toString()，返回原始字符串值</li></ul><p><strong>1. JavaScript 字符串</strong></p><p>JavaScript 字符串由 16 位码元（code unit）组成。对于大多数字符，每个码元对应一个字符</p><ul><li>length 属性表示字符串中码元的个数</li><li><s>charAt() 方法返回指定位置的码元，如果没有指定位置，则默认为 0</s></li><li><s>charCodeAt() 方法返回指定位置的码元的数值，如果没有指定位置，则默认为 0</s></li><li><s>fromCharCode() 方法接收一或多个码元值，然后将它们转换成字符串</s></li></ul><blockquote><p>对于 U+0000~U+FFFF 范围内的字符，上面的属性和方法返回的结果都跟预期是一样的</p><p>16 位只能唯一表示 2^16 个字符，这对于大多数语言字符集是足够了，在 Unicode 中称为<strong>基本多语言平面（BMP）</strong></p><p>为了表示更多的字符，Unicode 采用了一个策略，即每个字符使用另外 16 位去选择一个<strong>增补平面</strong>。这种每个字符使用两个 16 位码元的策略称为<strong>代理对（surrogate pair）</strong></p><p>在涉及增补平面的字符时，前面讨论的字符串方法和属性就会出问题</p></blockquote><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// &quot;smiling face with smiling eyes&quot; 表情符号的码点是 U+1F60A</span>
<span class="token comment">// 0x1F60A === 128522</span>
<span class="token keyword">let</span> message <span class="token operator">=</span> <span class="token string">&#39;ab😊de&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span>length<span class="token punctuation">)</span> <span class="token comment">// 6</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charAt</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;b&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charAt</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;�&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charAt</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;�&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charAt</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;d&#39;</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charCodeAt</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 98</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charCodeAt</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 55357</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charCodeAt</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 56842</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>message<span class="token punctuation">.</span><span class="token function">charCodeAt</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 100</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>String<span class="token punctuation">.</span><span class="token function">fromCharCode</span><span class="token punctuation">(</span><span class="token number">0x1f60a</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;�&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>String<span class="token punctuation">.</span><span class="token function">fromCodePoint</span><span class="token punctuation">(</span><span class="token number">0x1f60a</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;😊&#39;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>String<span class="token punctuation">.</span><span class="token function">fromCharCode</span><span class="token punctuation">(</span><span class="token number">97</span><span class="token punctuation">,</span> <span class="token number">98</span><span class="token punctuation">,</span> <span class="token number">55357</span><span class="token punctuation">,</span> <span class="token number">56842</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">101</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// &#39;ab😊de&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>码点</strong>是 Unicode 中一个字符的完整标识</p><p>迭代字符串可以智能地识别代理对的码点：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token operator">...</span><span class="token string">&#39;ab😊de&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">// [&#39;a&#39;, &#39;b&#39;, &#39;😊&#39;, &#39;d&#39;, &#39;e&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>codePointAt() 方法返回指定位置的码点，如果传入的码元索引并非代理对的开头，就会返回错误的码点</li><li>fromCodePoint() 方法接收一个或多个码点，然后将它们转换成字符串</li></ul><p><strong>2. normalize() 方法</strong></p><p>某些 Unicode 字符可以有多种编码方式，多种形式间使用 === 的结果为 false。为解决这个问题，ES6 提供了 normalize() 方法，用于将字符的不同表示方法统一为同样的形式，使用时需要传入表示哪种形式的字符串：&quot;NFC&quot;、&quot;NFD&quot;、&quot;NFKC&quot;、&quot;NFKD&quot;</p><p><strong>3. 字符串操作方法</strong></p><ul><li>concat()，拼接字符串</li><li>从字符串中提取子字符串，省略第二个参数即提取到末尾 <ul><li>slice()，接收两个参数，返回从第一个参数指定位置开始到第二个参数指定位置结束的子字符串。将所有负值参数都当成字符串长度加上负值参数</li><li>substr()，接收两个参数，返回从第一个参数指定位置开始到第二个参数指定的长度结束的子字符串。第二个负值参数会被转换为 0</li><li>substring()，与 slice() 类似，但所有负值参数值都会转换为 0</li></ul></li></ul><p><strong>4. 字符串位置方法</strong></p><ul><li>从字符串中搜索传入的字符串，并返回位置（如果没找到则返回 -1）。可以接收第二个参数，表示开始搜素的位置 <ul><li>indexOf()，从开头开始查找子字符串</li><li>lastIndexOf()，从末尾开始查找子字符串</li></ul></li></ul><p><strong>5. 字符串包含方法</strong></p><ul><li>判断字符串中是否包含另一个字符串，从字符串中搜索传入的字符串，并返回一个是否包含的布尔值 <ul><li>startsWith() <ul><li>判断字符串是否以另一个字符串开头，检查开始于索引 0 的匹配项</li><li>接收第二个参数，表示开始搜素的位置</li></ul></li><li>endsWith() <ul><li>判断字符串是否以另一个字符串结尾，检查开始于索引 length - searchStr.length 的匹配项</li><li>接收第二个参数，表示应该当作字符串末尾的位置（正则 $ 匹配的位置）</li></ul></li><li>includes() <ul><li>判断字符串是否包含另一个字符串，检查整个字符串</li><li>接收第二个参数，表示开始搜素的位置</li></ul></li></ul></li></ul><p><strong>6. trim() 方法</strong></p><p>去除字符串两端的空格，返回新字符串</p><p>trimLeft() / trimRight()，去除字符串左边 / 右边的空格，返回新字符串</p><p><strong>7. repeat() 方法</strong></p><p>接收一个整数参数，表示将原字符串重复多少次，返回新字符串</p><p><strong>8. padStart() / padEnd() 方法</strong></p><p>两个方法会复制字符串，如果小于指定长度，则在相应一边填充字符，直至满足长度条件</p><p>第一个参数是长度，第二个参数是可选的填充字符，默认为空格</p><p><strong>9. 字符串迭代与解构</strong></p><p>字符串的原型上暴露了一个 @@iterator 方法，表示可迭代字符串中的每个字符</p><p>手动使用迭代器：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> message <span class="token operator">=</span> <span class="token string">&#39;ab😊de&#39;</span>
<span class="token keyword">let</span> iterator <span class="token operator">=</span> message<span class="token punctuation">[</span>Symbol<span class="token punctuation">.</span>iterator<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>iterator<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// { value: &#39;a&#39;, done: false }</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>iterator<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// { value: &#39;b&#39;, done: false }</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>iterator<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// { value: &#39;😊&#39;, done: false }</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>iterator<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// { value: &#39;d&#39;, done: false }</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>iterator<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// { value: &#39;e&#39;, done: false }</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>iterator<span class="token punctuation">.</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// { value: undefined, done: true }</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 for-of 循环中可以通过这个迭代器按序访问每个字符：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> message <span class="token operator">=</span> <span class="token string">&#39;ab😊de&#39;</span>
<span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> c <span class="token keyword">of</span> message<span class="token punctuation">)</span> <span class="token punctuation">{</span>
	console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>c<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token comment">// &#39;a&#39;</span>
<span class="token comment">// &#39;b&#39;</span>
<span class="token comment">// &#39;😊&#39;</span>
<span class="token comment">// &#39;d&#39;</span>
<span class="token comment">// &#39;e&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>字符串也可以通过解构赋值的方式进行迭代：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> message <span class="token operator">=</span> <span class="token string">&#39;ab😊de&#39;</span>
<span class="token keyword">let</span> <span class="token punctuation">[</span>a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d<span class="token punctuation">,</span> e<span class="token punctuation">]</span> <span class="token operator">=</span> message
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d<span class="token punctuation">,</span> e<span class="token punctuation">)</span> <span class="token comment">// &#39;a&#39; &#39;b&#39; &#39;😊&#39; &#39;d&#39; &#39;e&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>10. 字符串大小写转换</strong></p><p>如果不知道代码涉及什么语言，则最好使用地区特定的转换方法</p><ul><li>toLowerCase()，将字符串转换为小写形式</li><li>toUpperCase()，将字符串转换为大写形式</li><li>toLocaleLowerCase()，将字符串转换为小写形式，基于特定地区实现</li><li>toLocaleUpperCase()，将字符串转换为大写形式，基于特定地区实现</li></ul><p><strong>11. 字符串模式匹配方法</strong></p><p>String 类型专门为在字符串中实现模式匹配设计了几个方法</p><ul><li>match()，本质跟 RegExp 的 exec() 方法相同</li><li>search()，返回模式第一个匹配的位置索引，如果没有找到则返回 -1</li><li>replace()</li></ul><p><strong>12. localeCompare() 方法</strong></p><p>因为返回的具体值可能因具体实现而异，所以最好像这样使用：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">determineOrder</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
	<span class="token keyword">let</span> result <span class="token operator">=</span> str1<span class="token punctuation">.</span><span class="token function">localeCompare</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
	<span class="token keyword">if</span> <span class="token punctuation">(</span>result <span class="token operator">&lt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;str1 comes before &#39;</span> <span class="token operator">+</span> value<span class="token punctuation">)</span>
	<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>result <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;str1 comes after &#39;</span> <span class="token operator">+</span> value<span class="token punctuation">)</span>
	<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
		console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;str1 is equal to &#39;</span> <span class="token operator">+</span> value<span class="token punctuation">)</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>localeCompare() 的独特之处在于，实现所在的地区（国家和语言）决定了这个方法如何比较字符串</p><h3 id="单例内置对象" tabindex="-1"><a class="header-anchor" href="#单例内置对象" aria-hidden="true">#</a> 单例内置对象</h3><p>ECMA-262 对内置对象的定义是“任何由 ECMAScript 实现提供、与宿主环境无关，并在 ECMAScript 程序开始执行时就存在的对象”，如前面接触的 Object、Array、String、Function、Date、RegExp、Error、Boolean、Number，包括接下来介绍的两个单例内置对象 Math、Global</p><h4 id="global" tabindex="-1"><a class="header-anchor" href="#global" aria-hidden="true">#</a> Global</h4><p>ECMA-262 规定 Global 对象为一种兜底对象，它所针对的是不属于任何对象的属性和方法。在全局作用域中定义的变量和函数都会变成 Global 对象的属性。isNaN()、isFinite()、parseInt() 和 parseFloat() 都是 Global 对象的方法，除了这些 ECMAScript 还为 Global 对象定义了其他方法</p><p><strong>1. URL 编码方法</strong></p><p>有效的 URI 不能包含某些字符，比如空格。使用 URI 编码方法可以让浏览器理解它们，同时又以特殊的 UTF-8 编码替换所有无效字符，比如空格会被替换成 %20</p><p>encodeURI()、encodeURIComponent()、decodeURI()、decodeURIComponent()，用于对 统一资源标识符（URI）进行编码和解码</p><ul><li>encodeURI()，主要用于整个 URI，不会对本身属于 URI 的特殊字符进行编码，比如冒号、正斜杠、问号和井号</li><li>encodeURIComponent()，主要用于对 URI 中的某一段进行编码，会对它发现的任何非标准字符进行编码</li></ul><p><strong>2. eval() 方法</strong></p><p>这个方法就是一个完整的 ECMAScript 解释器，它接收一个参数，即要执行的 ECMAScript（或 JavaScript）字符串</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token function">eval</span><span class="token punctuation">(</span><span class="token string">&#39;console.log(&quot;hi&quot;)&#39;</span><span class="token punctuation">)</span> <span class="token comment">// &#39;hi&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>3. Global 对象的属性</strong></p><ul><li>undefined、NaN、Infinity 等特殊值</li><li>原生引用类型构造函数，比如 Object、Array、String 等</li></ul><p><strong>4. window 对象</strong></p><p>虽然 ECMA-262 没有规定直接访问 Global 对象的方式，但浏览器将 window 对象实现为 Global 对象的代理</p><p>另一种获取 Global 对象的方式：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">var</span> global <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
	<span class="token keyword">return</span> <span class="token keyword">this</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="math" tabindex="-1"><a class="header-anchor" href="#math" aria-hidden="true">#</a> Math</h4><p>ECMAScript 提供了 Math 对象作为保存数学公式、信息和计算的地方。Math 对象提供了一些辅助计算的属性和方法</p><p><strong>1. Math 对象属性</strong></p><ul><li>Math.E，自然对数的底数，即常量 e 的值</li><li>Math.LN10，10 为底的自然对数</li><li>Math.LN2，2 为底的自然对数</li><li>Math.LOG2E，以 2 为底 e 的对数</li><li>Math.LOG10E，以 10 为底 e 的对数</li><li>Math.PI，π 的值</li><li>Math.SQRT1_2，1/2 的平方根</li><li>Math.SQRT2，2 的平方根</li></ul><p><strong>2. min() 和 max() 方法</strong></p><p>接收任意多个参数</p><p><strong>3. 舍入方法</strong></p><ul><li>Math.ceil()，向上取整</li><li>Math.floor()，向下取整</li><li>Math.floor()，四舍五入</li><li>Math.fround()，返回最接近参数的 32 位单精度浮点值表示</li></ul><p><strong>4. random 方法</strong></p><p>返回大于等于 0 小于 1 的一个随机数</p><p>可以基于如下公式使用 Math.random() 从一组整数中随机选择一个整数：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Math<span class="token punctuation">.</span><span class="token function">floor</span><span class="token punctuation">(</span>Math<span class="token punctuation">.</span><span class="token function">random</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">*</span> 可能值的总数 <span class="token operator">+</span> 第一个可能的值<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>5. 其他方法</strong></p>`,99),b={href:"https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Math#%E6%96%B9%E6%B3%95",target:"_blank",rel:"noopener noreferrer"};function h(f,j){const s=o("ExternalLinkIcon");return c(),l("div",null,[u,n("p",null,[n("a",r,[a("日期/时间组件方法"),t(s)])]),k,n("p",null,[n("a",d,[a("实例属性"),t(s)])]),n("p",null,[n("a",m,[a("实例方法"),t(s)])]),n("p",null,[n("a",v,[a("静态属性"),t(s)])]),g,n("p",null,[n("a",b,[a("Math 的方法"),t(s)])])])}const E=p(i,[["render",h],["__file","05.html.vue"]]);export{E as default};
